To register a networked object, use the networking API:

const api = getHoloScriptAPI()
api.networking.registerObject({
  id: 'player-123',
  x: 0, y: 0, z: 0,
  name: 'PlayerName',
  health: 100
})

This makes the object available to all connected clients for synchronization.

export function useNetworking() {
  const api = getHoloScriptAPI()
  const [syncedObjects, setSyncedObjects] = useState(new Map())
  const [objectCount, setObjectCount] = useState(0)

  useEffect(() => {
    const handleUpdate = ({ objectId, state }: { objectId: string; state: unknown }) => {
      setSyncedObjects(prev => new Map(prev).set(objectId, state))
    }

    api.networking.on('objectUpdated', handleUpdate)
    return () => api.networking.off('objectUpdated', handleUpdate)
  }, [api])

  return {
    syncedObjects,
    objectCount: syncedObjects.size,
    syncObject: api.networking.syncObject
  }
}

Use the physics API to create joints:

const api = getHoloScriptAPI()
api.physics.applyJoint('object1', 'object2', {
