export function useAnalytics() {
  const api = getHoloScriptAPI()
  const [eventCount, setEventCount] = useState(0)
  const [sessionId, setSessionId] = useState<string | null>(null)

  useEffect(() => {
    const session = api.analytics.startSession('Player')
    setSessionId(session.sessionId)

    const handleEvent = () => {
      setEventCount(api.analytics.eventCount)
    }

    api.analytics.on('eventTracked', handleEvent)
    return () => {
      api.analytics.off('eventTracked', handleEvent)
      api.analytics.endSession()
    }
  }, [api])

  return {
    trackEvent: api.analytics.trackEvent,
    eventCount,
    sessionId,
    exportCSV: api.analytics.exportAsCSV
  }
}

