export function PlayerHealthComponent() {
  const { networking, physics, analytics } = useAllSystems()
  const [health, setHealth] = useState(100)

  const takeDamage = (damage: number) => {
    const newHealth = Math.max(0, health - damage)
    setHealth(newHealth)

    // Track event
    analytics.trackEvent('damageTaken', {
      damage,
      health: newHealth,
      timestamp: Date.now()
    })

