    networking.syncObject('player-1', { health: newHealth })
  }

  return (
    <div>
      <div style={{
        width: `${health}%`,
        height: '20px',
        backgroundColor: health > 50 ? 'green' : 'red'
      }} />
      <button onClick={() => takeDamage(10)}>Take Damage</button>
    </div>
  )
}

