export function useGameLoop() {
  const api = getHoloScriptAPI()
  const all = useAllSystems()

  useEffect(() => {
    const gameLoop = async () => {
      // 1. Start analytics
      all.analytics.trackEvent('gameLoopStart', { timestamp: Date.now() })

      // 2. Register/update networking
      api.networking.syncObject('player-1', { x: 10, y: 20 })

      // 3. Run physics
      await api.physics.applySolver(5)

      // 4. Check party members
      if (all.party.currentParty) {
        all.party.currentParty.members.forEach(member => {
          api.networking.syncObject(member.id, { status: 'playing' })
        })
      }

      // 5. Queue offline updates
      if (!api.sync.isOnline) {
        api.sync.trackLocalUpdate({ objectId: 'player-1', state: { x: 10 } })
      }

      // 6. Sync via P2P
      api.network.syncObjectState('player-1', { x: 10, y: 20 })

      // 7. End event
      all.analytics.trackEvent('gameLoopEnd', { timestamp: Date.now() })
    }

    const interval = setInterval(gameLoop, 1000 / 60)  // 60 FPS
    return () => clearInterval(interval)
  }, [api, all])
}

