const api = getHoloScriptAPI()

const buildTower = (x: number, y: number, z: number, height: number) => {
  const blocks = []

  for (let i = 0; i < height; i++) {
    const blockId = `block-${x}-${y}-${i}`
    const blockZ = z + i * 2  // Stack blocks

    // Register block in network
    api.networking.registerObject({
      id: blockId,
      x,
      y,
      z: blockZ,
      type: 'block',
      mass: 1
    })

    blocks.push(blockId)

    // Add physics constraint to previous block
    if (i > 0) {
      api.physics.applyJoint(blocks[i - 1], blockId, {
        offset: [0, 0, 2]
      })
    }
  }

  // Run physics to stabilize
  api.physics.applySolver(20)

  // Sync all blocks
  blocks.forEach(blockId => {
    const block = api.networking.syncedObjects.get(blockId)
    api.networking.syncObject(blockId, block)
  })

  return blocks
}

