const setupRespawnSystem = (playerId: string) => {
  const respawnPoints = [
    { x: 0, y: 0, z: 0 },
    { x: 50, y: 50, z: 0 },
    { x: -50, y: -50, z: 0 }
  ]

  const handlePlayerDeath = () => {
    // Select random respawn point
    const respawn = respawnPoints[Math.floor(Math.random() * respawnPoints.length)]

    // Unregister dead player
    api.networking.unregisterObject(playerId)

    // Wait 3 seconds
    setTimeout(() => {
      // Re-register at respawn point
      api.networking.registerObject({
        id: playerId,
        x: respawn.x,
        y: respawn.y,
        z: respawn.z,
        health: 100
      })

      // Track event
      api.analytics.trackEvent('playerRespawned', {
        playerId,
        respawnPoint: respawn,
        timestamp: Date.now()
      })
    }, 3000)
  }

  // Listen for player death
  api.networking.on('objectDeleted', ({ objectId }) => {
    if (objectId === playerId) handlePlayerDeath()
  })
}

