export function Leaderboard() {
  const { analytics } = useAllSystems()
  const [rankings, setRankings] = useState<Array<{ name: string; score: number }>>([])

  useEffect(() => {
    const report = analytics.getSessionReport?.()
    if (report?.events) {
      const scores = new Map<string, number>()

      report.events.forEach(event => {
        if (event.type === 'playerKill' && event.data.killer) {
          scores.set(
            event.data.killer,
            (scores.get(event.data.killer) || 0) + 1
          )
        }
      })

      const sorted = Array.from(scores.entries())
        .map(([name, score]) => ({ name, score }))
        .sort((a, b) => b.score - a.score)
        .slice(0, 10)

      setRankings(sorted)
    }
  }, [analytics])

  return (
    <div>
      <h2>Leaderboard</h2>
      <ol>
        {rankings.map(({ name, score }) => (
          <li key={name}>{name}: {score} kills</li>
        ))}
      </ol>
    </div>
  )
}

