type GameState = 'waiting' | 'player1-turn' | 'player2-turn' | 'game-over'

const setupTurnBasedGame = () => {
  const [gameState, setGameState] = useState<GameState>('waiting')
  const [currentPlayer, setCurrentPlayer] = useState<string>('player-1')

  const startGame = () => {
    // Register both players
    api.networking.registerObject({
      id: 'player-1',
      x: 0, y: 0, z: 0,
      isActive: true
    })
    api.networking.registerObject({
      id: 'player-2',
      x: 10, y: 10, z: 0,
      isActive: false
    })

    setGameState('player1-turn')
    api.analytics.trackEvent('gameStarted', { timestamp: Date.now() })
  }

  const endTurn = () => {
    const nextPlayer = currentPlayer === 'player-1' ? 'player-2' : 'player-1'

    // Update active status
    api.networking.syncObject(currentPlayer, { isActive: false })
    api.networking.syncObject(nextPlayer, { isActive: true })

    setCurrentPlayer(nextPlayer)
    setGameState(nextPlayer === 'player-1' ? 'player1-turn' : 'player2-turn')

    api.analytics.trackEvent('turnEnded', {
      previousPlayer: currentPlayer,
      nextPlayer
    })
  }

  return { startGame, endTurn, gameState, currentPlayer }
}

