interface SafeZone {
  x: number
  y: number
  z: number
  radius: number
}

const safeZones: SafeZone[] = [
  { x: 0, y: 0, z: 0, radius: 20 },
  { x: 100, y: 100, z: 0, radius: 15 }
]

const isInSafeZone = (playerState: any): boolean => {
  return safeZones.some(zone => {
    const distance = Math.sqrt(
      Math.pow(playerState.x - zone.x, 2) +
      Math.pow(playerState.y - zone.y, 2) +
      Math.pow(playerState.z - zone.z, 2)
    )
    return distance <= zone.radius
  })
}

const damagePlayer = (playerId: string, damage: number) => {
  const playerState = api.networking.syncedObjects.get(playerId)

  if (isInSafeZone(playerState)) {
    console.log('Safe zone - damage blocked')
    api.analytics.trackEvent('damageBlocked', {
      playerId,
      reason: 'inSafeZone',
      attemptedDamage: damage
    })
    return false
  }

  // Deal damage
  const newHealth = Math.max(0, playerState.health - damage)
  api.networking.syncObject(playerId, { health: newHealth })

  api.analytics.trackEvent('damageDealt', {
    playerId,
    damage,
    newHealth
  })

  return true
}

const api = getHoloScriptAPI()

interface Skill {
  id: string
  name: string
  damage: number
  cooldown: number  // milliseconds
  lastUsed: number
}

export function useSkillSystem(playerId: string) {
  const [skills, setSkills] = useState<Map<string, Skill>>(new Map())

  const learnSkill = (skill: Skill) => {
    setSkills(new Map(skills).set(skill.id, {
      ...skill,
      lastUsed: 0
    }))
  }

  const canUseSkill = (skillId: string): boolean => {
    const skill = skills.get(skillId)
    if (!skill) return false

    const now = Date.now()
    return now - skill.lastUsed >= skill.cooldown
  }

  const useSkill = (skillId: string, targetId: string) => {
    if (!canUseSkill(skillId)) {
      console.log('Skill on cooldown')
      return false
    }

    const skill = skills.get(skillId)!

    // Update skill cooldown
    const updated = new Map(skills)
    updated.set(skillId, {
      ...skill,
      lastUsed: Date.now()
    })
    setSkills(updated)

    // Sync to other players
    api.networking.syncObject(playerId, { skillUsed: skillId })

    // Apply damage
    const target = api.networking.syncedObjects.get(targetId)
    const newHealth = Math.max(0, target.health - skill.damage)
    api.networking.syncObject(targetId, { health: newHealth })

    // Track event
    api.analytics.trackEvent('skillUsed', {
      playerId,
      skillId,
      skillName: skill.name,
      targetId,
      damage: skill.damage
    })

    return true
  }

  return { learnSkill, canUseSkill, useSkill, skills }
}
